"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[9798],{82666:e=>{e.exports=JSON.parse('{"functions":[{"name":"GetHandler","desc":"Returns the [PlayerHandler] for the given player, if it exists.","params":[{"name":"player","desc":"","lua_type":"Player"}],"returns":[{"desc":"","lua_type":"PlayerHandler?"}],"function_type":"method","source":{"line":123,"path":"src/Server/Services/PlayerRegistry.luau"}},{"name":"CreateHandler","desc":"Creates a new [PlayerHandler] for the given player with the specified [CharacterType].\\nIf a handler already exists for the player, it will be destroyed before creating a new one.","params":[{"name":"player","desc":"","lua_type":"Player"},{"name":"characterType","desc":"","lua_type":"CharacterType"}],"returns":[{"desc":"","lua_type":"PlayerHandler?"}],"function_type":"method","source":{"line":136,"path":"src/Server/Services/PlayerRegistry.luau"}},{"name":"_init","desc":"Initializes the player registry by setting up event listeners and remote handlers.","params":[],"returns":[],"function_type":"method","private":true,"source":{"line":165,"path":"src/Server/Services/PlayerRegistry.luau"}},{"name":"_setupRemoteHandlers","desc":"Sets up the remote event handlers for the player registry.","params":[],"returns":[],"function_type":"method","private":true,"source":{"line":183,"path":"src/Server/Services/PlayerRegistry.luau"}},{"name":"_onPlayerRemoving","desc":"Destroys the [PlayerHandler] for the given player when they leave the game.","params":[{"name":"player","desc":"","lua_type":"Player"}],"returns":[],"function_type":"method","private":true,"source":{"line":289,"path":"src/Server/Services/PlayerRegistry.luau"}}],"properties":[{"name":"_handlers","desc":"A dictionary mapping player user IDs to their respective [PlayerHandler] instances.","lua_type":"{ [number]: PlayerHandler }","private":true,"source":{"line":65,"path":"src/Server/Services/PlayerRegistry.luau"}}],"types":[],"name":"PlayerRegistry","desc":"PlayerRegistry is a singleton class that oversees the lifecycle of [PlayerHandler] instances for all players in the game. \\nIt acts as a bridge between remote events and player handlers, ensuring that events are routed to the appropriate handler methods. \\nBy managing handlers for different character types (e.g., [LobbyPlayerHandler], [RoundPlayerHandler]), it enables seamless \\ninteraction between players and the game state.\\n\\n### Core Responsibilities:\\n- **Handler Management:**\\n\\t- Tracks [PlayerHandler] instances, associating them with players via user IDs.\\n\\t- Dynamically creates handlers for players based on their current [CharacterType], such as [LobbyPlayerHandler] or [RoundPlayerHandler].\\n\\t- Automatically destroys handlers when players leave the game to clean up resources.\\n- **Event Routing:**\\n\\t- Listens to remote events fired by clients and delegates them to the corresponding [PlayerHandler] methods.\\n\\t- Ensures events are processed only by valid handlers that match the player\'s current state.\\n\\t- Performs validation of remote event arguments before invoking handler methods, ensuring security and consistency.\\n\\n### Features:\\n- **Dynamic Handler Creation:**\\n\\t- Supports multiple [PlayerHandler] subclasses, such as [LobbyPlayerHandler] and [RoundPlayerHandler], \\n\\t  allowing for flexible management of different game states.\\n\\t- Automatically transitions players between handlers as their [CharacterType] changes during gameplay.\\n- **Validation and Debugging:**\\n\\t- Ensures that remote events contain valid arguments, logging warnings for invalid or unauthorized attempts.\\n\\t- Helps maintain server integrity by preventing malformed or malicious data from affecting game logic.\\n\\nPlayerRegistry is an essential server-side utility for delegating event handling to the appropriate player handlers,\\nensuring secure and efficient management of player interactions throughout the game.","tags":["Singleton"],"realm":["Server"],"source":{"line":98,"path":"src/Server/Services/PlayerRegistry.luau"}}')}}]);